try {
  const raw = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  if (!raw) throw new Error('Empty Gemini response');

  const FENCE = String.fromCharCode(96, 96, 96);

  // ── Extract JSON string from response ──────────────────────
  function extractJsonStr(text) {
    // Try fence blocks first
    const fi = text.indexOf(FENCE);
    if (fi !== -1) {
      const after = text.slice(fi + 3);
      const stripped = after.toLowerCase().startsWith('json') ? after.slice(4) : after;
      const fe = stripped.indexOf(FENCE);
      const s = (fe !== -1 ? stripped.slice(0, fe) : stripped).trim();
      if (s.startsWith('{')) return s;
    }
    // Find outermost { ... }
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start !== -1 && end > start) return text.slice(start, end + 1);
    return text.trim();
  }

  // ── JSON sanitizer ─────────────────────────────────────────
  function sanitize(str) {
    return str
      .replace(/^\uFEFF/, '')
      .replace(/,\s*([}\]])/g, '$1')          // trailing commas
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');  // bad control chars
  }

  // ── Field-by-field regex extractor (nuclear fallback) ─────
  function extractFields(text) {
    const get = (key, isArr) => {
      if (isArr) {
        const m = text.match(new RegExp(`"${key}"\\s*:\\s*(\\[(?:[^\\[\\]]*|\\[[^\\[\\]]*\\])*\\])`));
        if (!m) return null;
        try { return JSON.parse(sanitize(m[1])); } catch(e) { return []; }
      }
      // String value
      const m = text.match(new RegExp(`"${key}"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"`));
      if (m) return m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
      // Number/bool
      const m2 = text.match(new RegExp(`"${key}"\\s*:\\s*([0-9.]+|true|false)`));
      if (m2) {
        const v = m2[1];
        if (v === 'true') return true;
        if (v === 'false') return false;
        return isNaN(v) ? v : Number(v);
      }
      return null;
    };
    return {
      is_agentic_relevant:  get('is_agentic_relevant') ?? true,
      headline:             get('headline') || '',
      headline_highlights:  get('headline_highlights', true) || [],
      summary:              get('summary') || '',
      full_article:         get('full_article') || '',
      image_prompt:         get('image_prompt') || '',
      image_search_query:   get('image_search_query') || '',
      linkedin:             get('linkedin') || '',
      facebook:             get('facebook') || '',
      source_url:           get('source_url') || '',
      subreddit:            get('subreddit') || '',
      reddit_url:           get('reddit_url') || '',
      date:                 get('date') || '',
      row_number:           get('row_number') || 0,
      confidence:           get('confidence') || 7,
      subject_type:         get('subject_type') || 'company',
      subject_name:         get('subject_name') || '',
      company_domain:       get('company_domain') || '',
      logo_search_query:    get('logo_search_query') || '',
    };
  }

  const jsonStr = extractJsonStr(raw);

  // Try 1: direct parse
  let parsed;
  try { parsed = JSON.parse(jsonStr); } catch(_) {}

  // Try 2: sanitize then parse
  if (!parsed) {
    try { parsed = JSON.parse(sanitize(jsonStr)); } catch(_) {}
  }

  // Try 3: field-by-field regex (works even on truncated/malformed JSON)
  if (!parsed || !parsed.headline) {
    parsed = extractFields(raw);
  }

  if (!parsed.headline) throw new Error('Could not extract headline from Gemini response');
  return [{ json: parsed }];
} catch(e) {
  const raw = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  return [{ json: { _parse_error: e.message, _raw: raw.substring(0, 3000) } }];
}

const tavilyResult = $input.item.json;
const images = tavilyResult.images || [];

// Score each image URL for likelihood of being a real press/portrait photo
function scoreImage(url) {
  let score = 0;
  // Prefer larger image hints
  if (/[_-](1200|1024|900|800|large|full|hires|hd|original)/i.test(url)) score += 3;
  // Prefer known press/media CDNs
  if (/(reuters|apimages|gettyimages|afp|bloomberg|wsj|nytimes|techcrunch|wired|theatlantic)/i.test(url)) score += 4;
  // Prefer portrait/headshot/profile signals
  if (/(portrait|headshot|profile|ceo|founder|speaker|press)/i.test(url)) score += 2;
  // Penalise noise
  if (/(logo|icon|favicon|thumb|banner|badge|avatar|placeholder|stock|generic|abstract)/i.test(url)) score -= 5;
  if (url.includes('.svg')) score -= 10;
  // Prefer jpg/jpeg/png
  if (/\.(jpg|jpeg|png)(\?|$)/i.test(url)) score += 1;
  return score;
}

const validImages = images
  .filter(url => typeof url === 'string' && url.length > 12)
  .map(url => ({ url, score: scoreImage(url) }))
  .filter(({ score }) => score >= -1)
  .sort((a, b) => b.score - a.score)
  .map(({ url }) => url);

const goodImage = validImages.length > 0 ? validImages[0] : null;
const claudeData = $('Confidence Gate').item.json;

// Ensure logo_search_query always has a value so Tavily Logo Search never gets empty query
const subjectName = claudeData.subject_name || '';
const headline = claudeData.headline || '';
let logoQuery = claudeData.logo_search_query || '';
if (!logoQuery.trim()) {
  // Build fallback from subject_name or first 3 words of headline
  if (subjectName) {
    logoQuery = `${subjectName} logo transparent PNG`;
  } else {
    const words = headline.split(' ').slice(0, 3).join(' ');
    logoQuery = `${words} logo PNG`;
  }
}

return [{
  json: {
    ...claudeData,
    press_image_url: goodImage,
    all_reference_images: validImages.slice(0, 5),
    has_press_image: !!goodImage,
    logo_search_query: logoQuery
  }
}];

const json = $input.item.json;
const urls = json.all_reference_images || [];
const base64Images = [];
for (const url of urls.slice(0, 5)) {
  try {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const base64 = Buffer.from(arrayBuffer).toString('base64');
    base64Images.push(base64);
  } catch (e) {}
}
return { json: { ...json, reference_base64_images: base64Images } };

parameters.jsonBody:
={{ (function() {
  const json = $input.item.json;
  const images = json.reference_base64_images || [];
  const logob64 = json.logo_base64 || null;
  const subjectName = json.subject_name || '';

  const parts = [
    {
      "text": `You are a professional news graphic designer. Refine the visual prompt for Seedream-v4 based on news context and reference photos.

CRITICAL RULE: Return ONLY the raw visual prompt text. No explanation, no markdown. Just the prompt.

Your job: read the headline and summary, then write a SCENE PROMPT that tells the story visually — like a film still or magazine editorial photo.

SCENE RULES:
- Ask yourself: what is the KEY VISUAL MOMENT of this news story?
- MEDIUM SHOT or ENVIRONMENTAL SHOT — show enough context to tell the story, not just a face
- If person is in reference photos: use their actual likeness (face, hair, clothing)
- If a logo image is provided: incorporate it NATURALLY in the scene — on a laptop lid, on a screen, on a building wall, on a product, on a t-shirt. Do NOT force it. Place it where it would realistically appear.

SCREEN / CONSOLE RULE:
- Screens showing blurred code, terminal output, or console text ARE allowed — they look realistic and tell the story
- Example: "monitor showing scrolling green terminal code", "laptop screen with dark IDE open, code visible"
- FORBIDDEN: floating text labels, speech bubbles, title cards, captions, name badges, explicit product name text written in the air

NO explicit text labels or captions floating in the scene. Natural screen/console content is fine.

SCENE EXAMPLES:
- AI model launch → person at desk amazed, laptop screen showing a chat interface with blurred text
- Cybersecurity → hooded figure at multiple monitors with scrolling terminal code, dim blue atmosphere
- GPU/hardware launch → engineer holding chip up, ${subjectName} logo visible on packaging behind them
- AI framework release → developer at desk with VS Code open, code on screen, coffee mug nearby
- Funding/deal → handshake in glass office, city skyline behind
- Robot/automation → humanoid robot or robotic arm in modern lab

NEVER: sci-fi holographic UI, floating interfaces, neon god rays, cartoon, anime, CGI, 3D render

Cinestill 800t film style. Sharp subject, contextual background.

NEWS HEADLINE: \${json.headline}
NEWS SUMMARY: \${json.summary}

` + (images.length > 0 ? "Reference photos provided — use the actual person's likeness." : "") + (logob64 ? ` Logo image provided — incorporate the ${subjectName} logo naturally in the scene where it would realistically appear.` : "")
    }
  ];

  // Add press photo references
  images.forEach(b64 => {
    parts.push({ "inline_data": { "mime_type": "image/jpeg", "data": b64 } });
  });

  // Add logo as a reference image so Gemini can see it
  if (logob64) {
    const logoMime = logob64.startsWith('/9j') ? 'image/jpeg' : 'image/png';
    parts.push({ "inline_data": { "mime_type": logoMime, "data": logob64 } });
  }

  return JSON.stringify({
    "contents": [{ "parts": parts }],
    "generationConfig": { "maxOutputTokens": 4096, "temperature": 0.4 }
  });
})() }}

