const json = $input.item.json;
let prompt = json.image_prompt;
try {
  const res = $('Gemini Visual Designer').item.json;
  let raw = res.candidates?.[0]?.content?.parts?.[0]?.text || '';
  if (raw.includes('**VISUAL PROMPT:**')) raw = raw.split('**VISUAL PROMPT:**')[1];
  else if (raw.includes('VISUAL PROMPT:')) raw = raw.split('VISUAL PROMPT:')[1];
  raw = raw.replace(/^(Here's|This is|I have refined|Designed as).*?[:\n]/si, '');
  raw = raw.replace(/\*\*/g, '').trim();
  if (raw) prompt = raw;
} catch (e) {}

const cleanPrompt = prompt.replace(/\\n/g, ' ').replace(/"/g, "'");

return [{
  json: {
    ...json,
    wavespeed_payload: {
      prompt: cleanPrompt + " -- cinestill 800t film grain, high fidelity editorial photo, real people real environments, story-driven scene, sharp focus on subject, natural cinematic lighting, screens may show blurred code or terminal output. NEGATIVE PROMPT: floating text labels, speech bubbles, captions, subtitles, title cards, name badges, watermark, text overlay, words floating in air, sci-fi, futuristic, holographic UI, floating interface, abstract digital art, CGI render, 3D render, illustration, anime, cartoon, fantasy",
      aspect_ratio: '4:5',
      output_format: 'png',
      enable_sync_mode: true
    }
  }
}];

// ============================================================
// HYPERSCALER NEWS CARD COMPOSITOR v6.2
// Composites text overlay onto AI-generated background
// V14: Logo passed as separate field to sharp-worker (librsvg fix)
// ============================================================

const geminiData = $('Confidence Gate').item.json;

let logo_base64 = null;
let logo_url_for_output = null;
let subjectType = 'company';

const binaryItems = $input.item.binary || {};
const binKeys = Object.keys(binaryItems);

// ── Binary resolution (n8n 2.x Buffer handling) ──────────────
const propName = binaryItems.data ? 'data' : (binKeys.length > 0 ? binKeys[0] : null);
if (!propName) {
  throw new Error('[Compositor] No binary found in input. Available keys: ' + binKeys.join(', '));
}

const testBuf = await this.helpers.getBinaryDataBuffer(0, propName);
if (!testBuf || testBuf.length < 100) {
  throw new Error(`[Compositor] Binary is only ${testBuf ? testBuf.length : 0} bytes — download failed or URL expired.`);
}

// Support JPEG & PNG magic bytes
const isPng = [0x89, 0x50, 0x4E, 0x47].every((b, i) => testBuf[i] === b);
const isJpeg = [0xFF, 0xD8, 0xFF].every((b, i) => testBuf[i] === b);
if (!isPng && !isJpeg) {
  const hex = Array.from(testBuf.slice(0, 4)).map(b => b.toString(16).padStart(2,'0')).join(' ');
  throw new Error(`[Compositor] Unsupported format (magic: ${hex}). WaveSpeed may have returned an error page.`);
}

// ---- Extract card data ----
const headline = (geminiData.headline || 'AI NEWS TODAY').toUpperCase().trim();
const highlights = (geminiData.headline_highlights || []).map(h => h.toUpperCase().trim());
const brandName = 'HYPERSCALER';

// ---- Build SVG overlay ----
const W = 1080;
const H = 1350;

function xmlEscape(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&apos;');
}

function colorizeWords(text, highlights) {
  // Build a set of individual highlight words for exact matching
  const highlightSet = new Set();
  for (const h of highlights) {
    // Split multi-word highlights and add each word individually
    String(h).toUpperCase().replace(/[^A-Z0-9 $]/g, '').split(' ')
      .filter(w => w.length >= 1)
      .forEach(w => highlightSet.add(w));
  }
  const words = text.split(' ');
  return words.map(word => {
    // Strip punctuation for comparison but preserve original for rendering
    const clean = word.replace(/[^A-Z0-9$]/g, '');
    // Exact match only — no substring matching to avoid false positives
    const isCyan = clean.length >= 1 && highlightSet.has(clean);
    return { word, isCyan };
  });
}

function wrapWords(colorWords, maxCharsPerLine) {
  const lines = [];
  let currentLine = [];
  let currentLen = 0;
  for (const cw of colorWords) {
    if (currentLen + cw.word.length + (currentLine.length > 0 ? 1 : 0) > maxCharsPerLine && currentLine.length > 0) {
      lines.push(currentLine);
      currentLine = [cw];
      currentLen = cw.word.length;
    } else {
      if (currentLine.length > 0) currentLen += 1;
      currentLen += cw.word.length;
      currentLine.push(cw);
    }
  }
  if (currentLine.length > 0) lines.push(currentLine);

  // Balance orphan last line if applicable
  if (lines.length > 1) {
    const lastLine = lines[lines.length - 1];
    const prevLine = lines[lines.length - 2];

    // If last line has 1 word and previous has > 2 words, balance it
    if (lastLine.length === 1 && prevLine.length > 2) {
      const lastLineStrLen = lastLine[0].word.length;
      if (lastLineStrLen <= 12) {
        lastLine.unshift(prevLine.pop());
      }
    }
  }

  return lines;
}

const colorWords = colorizeWords(headline, highlights);
// Wrap at 22 characters max per line
const wrappedLines = wrapWords(colorWords, 22);

// Calculate the longest line character count for dynamic scaling
let longestCharCount = 0;
for (const line of wrappedLines) {
    const charCount = line.reduce((sum, cw) => sum + cw.word.length, 0) + Math.max(0, line.length - 1);
    if (charCount > longestCharCount) {
        longestCharCount = charCount;
    }
}
if (longestCharCount === 0) longestCharCount = 10;

// Dynamic font scaling 
const targetMargin = 100;
const targetWidth = W - (targetMargin * 2); 
const charWidthFactor = 0.65; 
const calcFontSize = Math.round(targetWidth / (longestCharCount * charWidthFactor));

// Enforce bounds on font size
const minFontSize = 70;
const maxFontSize = 120;
const baseFontSize = Math.min(maxFontSize, Math.max(minFontSize, calcFontSize));

const lineHeight = baseFontSize * 1.15; 
const lineCount = wrappedLines.length;
const totalTextHeight = lineCount * lineHeight;

// V13: Push the text ensemble much lower, closer to the bottom edge
const bottomMargin = 80; // Significantly reduced from 130
const startY = H - bottomMargin - totalTextHeight + baseFontSize; 
const brandY = startY - baseFontSize - 80; // Reduced gap above text

let textSvg = '';
wrappedLines.forEach((line, lineIdx) => {
  const y = startY + (lineIdx * lineHeight);
  textSvg += `<text x="${W/2}" y="${y}" font-family="'Arial Black', 'Impact', sans-serif" font-size="${baseFontSize}" font-weight="900" text-anchor="middle" letter-spacing="-1" xml:space="preserve">`;
  line.forEach((cw, wi) => {
    const color = cw.isCyan ? '#00D4FF' : '#FFFFFF';
    textSvg += `<tspan fill="${color}">${xmlEscape(cw.word)}</tspan>`;
    if (wi < line.length - 1) textSvg += ' '; 
  });
  textSvg += `</text>`;
});

// V13: Move gradient start lower to reveal more of the top image
const GRAD_START_FRAC = 0.45; // Moved down from 0.35
const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}">
  <defs>
    <linearGradient id="darkGrad" x1="0" y1="0" x2="0" y2="1">
      <stop offset="${GRAD_START_FRAC}" stop-color="#000000" stop-opacity="0"/>
      <stop offset="0.75" stop-color="#060810" stop-opacity="0.95"/>
      <stop offset="1" stop-color="#000000" stop-opacity="1"/>
    </linearGradient>
    <filter id="textShadow" x="-5%" y="-5%" width="110%" height="110%">
      <feDropShadow dx="0" dy="4" stdDeviation="8" flood-color="#000000" flood-opacity="0.9"/>
    </filter>
  </defs>
  <rect x="0" y="0" width="${W}" height="${H}" fill="url(#darkGrad)"/>

  <!-- GETINTOAI Style Brand Divider -->
  <line x1="140" y1="${brandY}" x2="${W/2 - 145}" y2="${brandY}" stroke="#FFFFFF" stroke-width="1.5" opacity="0.6"/>
  <text x="${W/2}" y="${brandY + 8}" font-family="'Arial', sans-serif" font-size="24" font-weight="500" fill="#FFFFFF" text-anchor="middle" letter-spacing="4" filter="url(#textShadow)">${xmlEscape(brandName)}</text>
  <line x1="${W/2 + 145}" y1="${brandY}" x2="${W - 140}" y2="${brandY}" stroke="#FFFFFF" stroke-width="1.5" opacity="0.6"/>

  <g filter="url(#textShadow)">${textSvg}</g>
${(function() {
  if (!logo_base64) return '';
  const cx = 918, cy = 158, r = 100;
  const ro = r + 14; // outer metallic ring radius
  return `
    <defs>
      <!-- Metallic ring gradient -->
      <linearGradient id="ringGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%"   stop-color="#d0d0d0"/>
        <stop offset="35%"  stop-color="#707070"/>
        <stop offset="65%"  stop-color="#404040"/>
        <stop offset="100%" stop-color="#1a1a1a"/>
      </linearGradient>
      <!-- Cyan glow ring gradient -->
      <linearGradient id="cyanRingGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%"   stop-color="#00D4FF" stop-opacity="1"/>
        <stop offset="50%"  stop-color="#0099CC" stop-opacity="0.8"/>
        <stop offset="100%" stop-color="#00D4FF" stop-opacity="0.6"/>
      </linearGradient>
      <!-- Glass highlight inside lens -->
      <radialGradient id="glassHL" cx="35%" cy="28%" r="55%">
        <stop offset="0%"   stop-color="white" stop-opacity="0.35"/>
        <stop offset="60%"  stop-color="white" stop-opacity="0.05"/>
        <stop offset="100%" stop-color="white" stop-opacity="0"/>
      </radialGradient>
      <!-- Logo background dark radial -->
      <radialGradient id="lensBg" cx="50%" cy="50%" r="50%">
        <stop offset="0%"   stop-color="#111111"/>
        <stop offset="100%" stop-color="#000000"/>
      </radialGradient>
      <!-- Drop shadow filter -->
      <filter id="lensShadow" x="-30%" y="-30%" width="160%" height="160%">
        <feDropShadow dx="0" dy="8" stdDeviation="16" flood-color="#000000" flood-opacity="0.75"/>
      </filter>
      <!-- Cyan outer glow -->
      <filter id="cyanGlow" x="-20%" y="-20%" width="140%" height="140%">
        <feGaussianBlur stdDeviation="6" result="blur"/>
        <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
      </filter>
    </defs>

    <!-- Outer drop shadow base -->
    <circle cx="${cx}" cy="${cy}" r="${ro + 2}" fill="#000" opacity="0.01" filter="url(#lensShadow)"/>

    <!-- Cyan glow outer ring -->
    <circle cx="${cx}" cy="${cy}" r="${ro + 4}" fill="none" stroke="url(#cyanRingGrad)" stroke-width="3" opacity="0.9" filter="url(#cyanGlow)"/>

    <!-- Metallic outer ring -->
    <circle cx="${cx}" cy="${cy}" r="${ro}" fill="url(#ringGrad)"/>

    <!-- Thin white inner border -->
    <circle cx="${cx}" cy="${cy}" r="${r + 2}" fill="none" stroke="white" stroke-width="1.5" opacity="0.25"/>

    <!-- Lens dark background -->
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#lensBg)"/>

    <!-- Logo image is now composited by sharp-worker natively (librsvg cannot render base64 images) -->

    <!-- Glass reflection highlight overlay -->
    <circle cx="${cx}" cy="${cy}" r="${r}" fill="url(#glassHL)"/>

    <!-- Cyan crosshair tick marks (camera viewfinder style) -->
    <line x1="${cx}" y1="${cy - ro - 10}" x2="${cx}" y2="${cy - ro + 6}" stroke="#00D4FF" stroke-width="2" opacity="0.8"/>
    <line x1="${cx}" y1="${cy + ro - 6}" x2="${cx}" y2="${cy + ro + 10}" stroke="#00D4FF" stroke-width="2" opacity="0.8"/>
    <line x1="${cx - ro - 10}" y1="${cy}" x2="${cx - ro + 6}" y2="${cy}" stroke="#00D4FF" stroke-width="2" opacity="0.8"/>
    <line x1="${cx + ro - 6}" y1="${cy}" x2="${cx + ro + 10}" y2="${cy}" stroke="#00D4FF" stroke-width="2" opacity="0.8"/>

    <!-- Corner arc brackets (top-left, top-right) -->
    <path d="M ${cx - ro - 6} ${cy - 18} A ${ro + 6} ${ro + 6} 0 0 1 ${cx - 18} ${cy - ro - 6}" fill="none" stroke="#00D4FF" stroke-width="2" opacity="0.5"/>
    <path d="M ${cx + 18} ${cy - ro - 6} A ${ro + 6} ${ro + 6} 0 0 1 ${cx + ro + 6} ${cy - 18}" fill="none" stroke="#00D4FF" stroke-width="2" opacity="0.5"/>`;
})()}
</svg>`;

const svgBase64 = Buffer.from(svg).toString('base64');
const bgBase64 = testBuf.toString('base64');

return [{
  json: { 
    ...geminiData, 
    compositor_mode: 'svg_overlay', 
    svg_overlay_base64: svgBase64, 
    bg_image_base64: bgBase64, 
    logo_base64: logo_base64 || null,
    logo_url: logo_url_for_output || null,
    company_domain: $input.item.json.company_domain || '',
    image_source: 'wavespeed_seedream' 
  },
  binary: {
    bg_image: binaryItems[propName] || { data: bgBase64, mimeType: isPng ? 'image/png' : 'image/jpeg', fileName: 'background.' + (isPng ? 'png' : 'jpg') },
    svg_overlay: { data: svgBase64, mimeType: 'image/svg+xml', fileName: 'overlay.svg' }
  }
}];

const bin = $input.item.binary || {};
const finalBin = bin.final_card || bin.data || Object.values(bin)[0] || null;
if (!finalBin) throw new Error('No final card binary found.');
return [{ json: $input.item.json, binary: { final_card: finalBin } }];

// Robustly extract the WaveSpeed generated image URL from multiple possible response shapes
const resp = $input.item.json;

const url =
  resp?.data?.outputs?.[0] ||
  resp?.outputs?.[0] ||
  resp?.data?.images?.[0] ||
  resp?.images?.[0] ||
  resp?.data?.url ||
  resp?.url ||
  resp?.data?.result ||
  resp?.result;

if (!url || typeof url !== 'string' || !url.startsWith('http')) {
  const raw = JSON.stringify(resp).slice(0, 500);
  throw new Error(`[WaveSpeed] Could not extract image URL from response. Tried data.outputs[0], outputs[0], data.images[0], images[0], data.url, url. Raw response: ${raw}`);
}

return [{ json: { ...$input.item.json, wavespeed_image_url: url } }];

const items = $input.all();
if (items.length === 0) return [];

// --- ROBUST FILTER: Only process items manually marked as "Approved" ---
const approved = items.filter(item => {
  const status = item.json['Status'] || '';
  return status.includes('Approved') || status === 'Approved';
});

if (approved.length === 0) {
  console.log('No approved items found in this batch.');
  return [];
}

// Sort by Engagement Score descending
const sorted = approved.sort((a, b) => (parseInt(b.json['Engagement Score']) || 0) - (parseInt(a.json['Engagement Score']) || 0));

// Pick the top one for processing
const selected = sorted.slice(0, 1);

// Map headers to internal briefing keys for compatibility
return selected.map(item => ({
  json: {
    row_number: item.json.row_number,
    title: item.json['Title'],
    text: item.json['Body'],
    author: item.json['Author'],
    original_score: item.json['Upvotes'],
    source_url: item.json['Article Link'] || item.json['URL'],
